const API_BASE_URL = process.env.REACT_APP_API_URL || '';

class ApiService {
  async request(endpoint, options = {}) {
    const url = `${API_BASE_URL}${endpoint}`;

    const config = {
      headers: {
        'Content-Type': 'application/json',
        ...options.headers,
      },
      ...options,
    };

    try {
      const response = await fetch(url, config);

      if (!response.ok) {
        throw new Error(`HTTP error! status: ${response.status}`);
      }

      return await response.json();
    } catch (error) {
      console.error('API request failed:', error);
      throw error;
    }
  }

  // Authentication endpoints
  async loginDoctor(credentials) {
    return this.request('/api/login-doctor', {
      method: 'POST',
      body: JSON.stringify(credentials),
    });
  }

  // Patient endpoints
  async registerPatient(patientData) {
    return this.request('/api/register-patient', {
      method: 'POST',
      body: JSON.stringify(patientData),
    });
  }

  async getPatients(day) {
    const query = day ? `?day=${day}` : '';
    return this.request(`/api/patients${query}`);
  }

  async callNextPatient(day) {
    return this.request('/api/call-next', {
      method: 'POST',
      body: JSON.stringify({ day }),
    });
  }
}

export default new ApiService();
